// ═══════════════════════════════════════════════════════════
// Ajusta formato para Google Docs — Code Node (v5)
// Mudanças sobre v4:
//   - Força bold nos headers "Pontos de Destaque" e "Action Items"
//   - Retorna doc_link e fileName para notificação WhatsApp
// ═══════════════════════════════════════════════════════════

// ─── 1. Leitura de inputs ───
// Transcricao: tenta multiplos caminhos do output do Gemini
const geminiOut = $('Transcreve com Google Gemini').first().json || {};
const transcription = geminiOut?.content?.parts?.[0]?.text
  || geminiOut?.text
  || geminiOut?.response?.generations?.[0]?.[0]?.text
  || geminiOut?.output
  || '';

// Summary: tenta multiplos caminhos do output do chainLlm
const chainOut = $input.first().json || {};
const summary = String(
  chainOut?.response?.generations?.[0]?.[0]?.text
  || chainOut?.response?.text
  || (typeof chainOut?.response === 'string' ? chainOut.response : '')
  || chainOut?.text
  || chainOut?.output
  || ''
).trim();

const docId = String(
  $('Criar Documento no Google Docs').first().json?.id
  || $('Criar Documento no Google Docs').first().json?.documentId
  || ''
).trim();

const fileName = $('Detecta novo upload no Drive').first().json?.name?.replace(/\.[^/.]+$/, '') || 'Documento';
const docLink = `https://docs.google.com/document/d/${docId}/edit`;

// ─── 2. Validação ───
if (!docId) {
  const rawDocNode = JSON.stringify($('Criar Documento no Google Docs').first().json || {}).substring(0, 300);
  throw new Error('[meet2docs] doc_id ausente. Output do node Google Docs: ' + rawDocNode);
}
if (!summary) {
  const rawChain = JSON.stringify(chainOut || {}).substring(0, 500);
  const keys = Object.keys(chainOut || {}).join(', ');
  throw new Error('[meet2docs] Resumo vazio. Keys: [' + keys + ']. Output: ' + rawChain);
}

// ─── 3. Monta documento: RESUMO + TRANSCRIÇÃO ───
const SUMMARY_HEADER       = '📋 RESUMO\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
const TRANSCRIPTION_HEADER = '\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎙 TRANSCRIÇÃO COMPLETA\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

const fullText = SUMMARY_HEADER
  + summary
  + TRANSCRIPTION_HEADER
  + (transcription || '(Transcrição não disponível)');

let text = fullText.replace(/\r\n/g, '\n');

// ─── 4. Parser de estilos (bold, italic, bullets) ───
let plainText = '';
const styles  = [];
const bullets = [];
let cursor = 1;

// Headers que DEVEM ser bold (mesmo que o LLM não tenha usado **)
const FORCE_BOLD_PATTERNS = [
  /✦\s*Pontos de Destaque/i,
  /📋\s*Procedimentos Identificados/i,
  /💡\s*Sugest/i,
  /🔀\s*Discuss/i,
  /✓\s*Action Items/i,
  /⚠\s*An[aá]lise Cr[ií]tica/i
];

const lines = text.split('\n');

for (let line of lines) {
  if (!line.trim()) {
    plainText += '\n';
    cursor++;
    continue;
  }

  const lineStartCursor = cursor;

  // Detecta se esta linha é um header que deve ser forçado bold
  let forceBoldThisLine = false;
  for (const pattern of FORCE_BOLD_PATTERNS) {
    if (pattern.test(line)) {
      forceBoldThisLine = true;
      break;
    }
  }

  // Detecta bullets (✦, ✓, 📋, 💡, 🔀, ⚠ ou -)
  let isBullet = false;
  const trimmed = line.trim();
  const bulletPrefixes = ['✦', '✓', '📋', '💡', '🔀', '⚠', '-'];
  const matchedPrefix = bulletPrefixes.find(p => trimmed.startsWith(p));
  if (matchedPrefix) {
    // Headers não viram bullet list
    if (!forceBoldThisLine) {
      isBullet = true;
      line = trimmed.substring(matchedPrefix.length).trim();
    }
  }

  // Parse markdown bold/italic
  const regex = /(\*\*([^*]+)\*\*|\*([^*]+)\*|([^*]+))/g;
  let match;
  while ((match = regex.exec(line)) !== null) {
    const raw   = match[0];
    const clean = match[2] || match[3] || match[4] || '';
    if (!clean) continue;

    const start = cursor;
    const end   = cursor + clean.length;

    plainText += clean;

    if (raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { bold: true },
        fields: 'bold'
      });
    } else if (raw.startsWith('*') && !raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { italic: true },
        fields: 'italic'
      });
    }

    cursor = end;
  }

  plainText += '\n';
  cursor++;

  // Força bold na linha inteira se for header
  if (forceBoldThisLine) {
    styles.push({
      range: { startIndex: lineStartCursor, endIndex: cursor - 1 },
      textStyle: { bold: true },
      fields: 'bold'
    });
  }

  if (isBullet) {
    bullets.push({
      range: {
        startIndex: lineStartCursor,
        endIndex: cursor
      },
      bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
    });
  }
}

// ─── 5. Monta requests para documents.batchUpdate ───
const requests = [];

requests.push({
  insertText: {
    endOfSegmentLocation: {},
    text: plainText
  }
});

for (const s of styles) {
  requests.push({
    updateTextStyle: {
      range: s.range,
      textStyle: s.textStyle,
      fields: s.fields
    }
  });
}

for (const b of bullets) {
  requests.push({
    createParagraphBullets: b
  });
}

// ─── 6. Retorna requests + doc_id + doc_link + fileName ───
return [{ json: { requests, doc_id: docId, doc_link: docLink, file_name: fileName } }];

